class MainActivity : ComponentActivity() {
    private lateinit var viewModel: MainViewModel

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions()
    ) { permissions ->
        if (permissions.all { it.value }) {
            viewModel.loadSms()
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        viewModel = ViewModelProvider(this)[MainViewModel::class.java]

        requestPermissions()

        setContent {
            CourtAssistantTheme {
                Surface(modifier = Modifier.fillMaxSize()) {
                    Navigation(viewModel = viewModel)
                }
            }
        }
    }

    private fun requestPermissions() {
        val needed = arrayOf(
            Manifest.permission.READ_SMS,
            Manifest.permission.READ_CALENDAR,
            Manifest.permission.WRITE_CALENDAR
        ).filter {
            ContextCompat.checkSelfPermission(this, it) != PackageManager.PERMISSION_GRANTED
        }.toTypedArray()

        if (needed.isEmpty()) {
            viewModel.loadSms()
        } else {
            permissionLauncher.launch(needed)
        }
    }
}

package com.court.assistant.pdf

import android.content.Context
import android.webkit.CookieManager
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File

class PdfDownloadManager(private val context: Context) {
    private val client = OkHttpClient.Builder()
        .followRedirects(true)
        .followSslRedirects(true)
        .build()

    fun getStorageDir(): File {
        val dir = File(context.getExternalFilesDir(null), "Documents")
        if (!dir.exists()) dir.mkdirs()
        return dir
    }

    suspend fun download(url: String, fileName: String? = null, cookies: String? = null): DownloadResult = withContext(Dispatchers.IO) {
        try {
            val requestBuilder = Request.Builder().url(url)
            val cookie = cookies ?: CookieManager.getInstance()?.getCookie(url)
            if (cookie != null) {
                requestBuilder.addHeader("Cookie", cookie)
            }
            val response = client.newCall(requestBuilder.build()).execute()
            if (!response.isSuccessful) return@withContext DownloadResult.Error("HTTP ${response.code}")

            val contentDisposition = response.header("Content-Disposition")
            val resolvedName = fileName
                ?: parseFileNameFromDisposition(contentDisposition)
                ?: "document_${System.currentTimeMillis()}.pdf"

            val safeName = resolvedName.replace(Regex("[\\/:*?\"<>|]"), "_")
            val file = File(getStorageDir(), safeName)
            response.body?.byteStream()?.use { input ->
                file.outputStream().use { output -> input.copyTo(output) }
            }
            DownloadResult.Success(file.absolutePath, safeName, file.length())
        } catch (e: Exception) {
            DownloadResult.Error(e.message ?: "Download failed")
        }
    }

    private fun parseFileNameFromDisposition(header: String?): String? {
        if (header == null) return null
        // filename*=UTF-8''xxx.pdf
        Regex("filename\*=(?:UTF-8''|utf-8'')(.+)").find(header)?.let {
            return java.net.URLDecoder.decode(it.groupValues[1], "UTF-8")
        }
        // filename="xxx.pdf"
        Regex("filename=\"?([^\"]+)\"?").find(header)?.let {
            return it.groupValues[1].trim()
        }
        return null
    }
}

sealed class DownloadResult {
    data class Success(val filePath: String, val fileName: String, val fileSize: Long) : DownloadResult()
    data class Error(val message: String) : DownloadResult()
}

package com.court.assistant.ui

import androidx.compose.runtime.Composable
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import androidx.navigation.navArgument
import com.court.assistant.viewmodel.MainViewModel

@Composable
fun Navigation(viewModel: MainViewModel) {
    val navController = rememberNavController()

    NavHost(navController = navController, startDestination = "main") {
        composable("main") {
            MainScreen(
                viewModel = viewModel,
                onOpenWebView = { smsId, url ->
                    navController.navigate("webview/$smsId/${java.net.URLEncoder.encode(url, "UTF-8")}")
                },
                onOpenPdf = { pdfId ->
                    navController.navigate("pdf/$pdfId")
                }
            )
        }
        composable(
            "webview/{smsId}/{url}",
            arguments = listOf(
                navArgument("smsId") { type = NavType.LongType },
                navArgument("url") { type = NavType.StringType }
            )
        ) { entry ->
            val smsId = entry.arguments?.getLong("smsId") ?: return@composable
            val url = java.net.URLDecoder.decode(entry.arguments?.getString("url") ?: "", "UTF-8")
            WebViewScreen(
                viewModel = viewModel,
                smsId = smsId,
                url = url,
                onBack = { navController.popBackStack() }
            )
        }
        composable(
            "pdf/{pdfId}",
            arguments = listOf(navArgument("pdfId") { type = NavType.LongType })
        ) { entry ->
            val pdfId = entry.arguments?.getLong("pdfId") ?: return@composable
            PdfPreviewScreen(
                viewModel = viewModel,
                pdfId = pdfId,
                onBack = { navController.popBackStack() }
            )
        }
    }
}

